@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun AgentScreen() {
    val context = LocalContext.current
    val vm: AgentViewModel = viewModel(
        factory = AgentViewModel.Factory(context.applicationContext as android.app.Application)
    )
    val messages by vm.messages.collectAsStateWithLifecycle()
    val isLoading by vm.isLoading.collectAsStateWithLifecycle()

    var input by remember { mutableStateOf("") }
    val listState = rememberLazyListState()

    // Scroll to bottom when a new message arrives
    LaunchedEffect(messages.size) {
        if (messages.isNotEmpty()) {
            listState.animateScrollToItem(messages.size - 1)
        }
    }

    Column(modifier = Modifier.fillMaxSize()) {
        TopAppBar(
            title = {
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Icon(
                        Icons.Default.AutoAwesome,
                        contentDescription = null,
                        modifier = Modifier.size(20.dp),
                        tint = MaterialTheme.colorScheme.primary
                    )
                    Spacer(Modifier.width(8.dp))
                    Text("AI Assistant", fontWeight = FontWeight.SemiBold)
                }
            },
            actions = {
                if (messages.isNotEmpty()) {
                    IconButton(onClick = vm::clearHistory) {
                        Icon(Icons.Default.Delete, contentDescription = "Clear chat")
                    }
                }
            }
        )

        if (messages.isEmpty()) {
            EmptyChatHint(modifier = Modifier.weight(1f))
        } else {
            LazyColumn(
                state = listState,
                modifier = Modifier
                    .weight(1f)
                    .padding(horizontal = 12.dp),
                verticalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                item { Spacer(Modifier.height(4.dp)) }
                items(messages) { msg ->
                    MessageBubble(msg)
                }
                if (isLoading) {
                    item { TypingIndicator() }
                }
                item { Spacer(Modifier.height(4.dp)) }
            }
