            text = if (work.isCompleted) "Done" else "Assignment",
            style = MaterialTheme.typography.labelSmall,
            color = if (work.isCompleted)
                MaterialTheme.colorScheme.onSurfaceVariant
            else
                MaterialTheme.colorScheme.secondary
        )
    }
}

