                    )
                    HorizontalDivider(color = MaterialTheme.colorScheme.outlineVariant)
                }

                // ── Local results ─────────────────────────────────────────────
                if (results.isEmpty()) {
                    item {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(horizontal = 16.dp, vertical = 20.dp),
                            contentAlignment = Alignment.Center
